                        context.EvaluatedKeywordForProperty(false, 7, RequiredPropertyTargetVersionNumberNotPresent, "targetVersionNumber"u8, "required"u8);
                    }
                    else
                    {
                        context.EvaluatedKeywordForProperty(true, 7, RequiredPropertyTargetVersionNumberPresent, "targetVersionNumber"u8, "required"u8);
                    }

                    if ((requiredPropertyChildHandler_seenItems[RequiredOffsetForTargetWorkflowId] & RequiredBitForTargetWorkflowId) == 0)
                    {
                        context.EvaluatedKeywordForProperty(false, 8, RequiredPropertyTargetWorkflowIdNotPresent, "targetWorkflowId"u8, "required"u8);
                    }
                    else
                    {
                        context.EvaluatedKeywordForProperty(true, 8, RequiredPropertyTargetWorkflowIdPresent, "targetWorkflowId"u8, "required"u8);
                    }

                    if ((requiredPropertyChildHandler_seenItems[RequiredOffsetForTimeZone] & RequiredBitForTimeZone) == 0)
                    {
                        context.EvaluatedKeywordForProperty(false, 9, RequiredPropertyTimeZoneNotPresent, "timeZone"u8, "required"u8);
                    }
                    else
                    {
                        context.EvaluatedKeywordForProperty(true, 9, RequiredPropertyTimeZonePresent, "timeZone"u8, "required"u8);
                    }
                }
            }
        }

        internal static bool Evaluate(
            IJsonDocument parentDocument,
            int parentIndex,
            IJsonSchemaResultsCollector? resultsCollector = null)
        {
            JsonSchemaContext context = JsonSchemaContext.BeginContext(
            parentDocument,
            parentIndex,
            usingEvaluatedItems: false,
            usingEvaluatedProperties: false,
            resultsCollector: resultsCollector);

            try
            {
                Evaluate(parentDocument, parentIndex, ref context);
                context.EndContext();
                return context.IsMatch;
            }
            finally
            {
                context.Dispose();
            }
        }

